        public void ABul()
        {
            if (this.KabinRayStr.SelectedIndex != -1)
            {
                MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
                connection.Open();
                MySqlDataReader reader = new MySqlCommand("select  s  from  ray where model ='" + this.KabinRayStr.Text + "'", connection).ExecuteReader();
                try
                {
                    if (reader.HasRows)
                    {
                        while (reader.Read())
                        {
                            this.A = Convert.ToDouble(reader[0].ToString()) * 100.0;
                        }
                    }
                }
                catch (Exception)
                {
                    MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
                }
                finally
                {
                    connection.Close();
                }
            }
        }

        private void addtoarraye(string gelenx, object donenx)
        {
            this.gelen.Add(gelenx);
            this.donen.Add(donenx.ToString());
        }

        private void aToolStripMenuItem_Click(object sender, EventArgs e)
        {
            this.listView1.Items.Clear();
            string[] files = Directory.GetFiles(this.startuppath + @"\teknik\", "*.*");
            for (int i = 0; i < files.Length; i++)
            {
                if (Path.GetExtension(files[i]) == ".doc")
                {
                    this.listView1.Items.Add(Path.GetFileNameWithoutExtension(files[i]), 0);
                }
            }
        }

