        public void Diger()
        {
            this.frmh2.dataGridView1.Rows.Clear();
            this.frmh2.dataGridView1.Rows.Add(10);
            if (this.textBox10.Text == "")
            {
                this.AdetUst = 0.0;
            }
            else
            {
                this.AdetUst = Convert.ToInt32(this.textBox10.Text);
            }
            this.Gtu = this.gn * ((this.Kaküt + this.KapiAgirlik) + this.Byük);
            this.Mee = (this.Gtu / 2.0) * (this.LUst / 2.0);
            this.Gerilmeee = this.Mee / (this.AdetUst * this.WUst);
            if (this.Gerilmeee < 90.0)
            {
                this.frmh2.dataGridView1.Rows[0].Cells[1].Style.BackColor = Color.White;
                this.frmh2.dataGridView1[0, 0].Value = "1";
                this.frmh2.dataGridView1[1, 0].Value = "KABİN \x00dcST ASKI KİRİŞLERİNİN EĞİLME HESABI UYGUNDUR !";
                this.frmh2.dataGridView1[2, 0].Value = true;
            }
            else
            {
                this.frmh2.dataGridView1[0, 0].Value = "1";
                this.frmh2.dataGridView1.Rows[0].Cells[1].Style.BackColor = Color.Red;
                this.frmh2.dataGridView1[1, 0].Value = "KABİN \x00dcST ASKI KİRİŞLERİNİN EĞİLME HESABI UYGUN DEĞİLDİR !";
                this.frmh2.dataGridView1[2, 0].Value = false;
                this.frmh2.dataGridView1[3, 0].Value = "\x00dcst askı kirişi değeri ve adetini artırın... ";
            }
            this.Sehim = (this.Gtu * Math.Pow(this.LUst, 3.0)) / ((10080000.0 * this.LxUst) * this.AdetUst);
            this.SehimSonuc = this.Sehim / this.LUst;
            if (this.SehimSonuc < 0.001)
            {
                this.frmh2.dataGridView1.Rows[1].Cells[1].Style.BackColor = Color.White;
                this.frmh2.dataGridView1[0, 1].Value = "2";
                this.frmh2.dataGridView1[1, 1].Value = "KABİN \x00dcST ASKI KİRİŞLERİNİN SEHİMİ HESABI UYGUNDUR !";
                this.frmh2.dataGridView1[2, 1].Value = true;
            }
            else
            {
                this.frmh2.dataGridView1[0, 1].Value = "2";
                this.frmh2.dataGridView1.Rows[1].Cells[1].Style.BackColor = Color.Red;
                this.frmh2.dataGridView1[1, 1].Value = "KABİN \x00dcST ASKI KİRİŞLERİNİN SEHİMİ HESABI UYGUN DEĞİLDİR !";
                this.frmh2.dataGridView1[2, 1].Value = false;
                this.frmh2.dataGridView1[3, 1].Value = "\x00dcst askı kirişi değeri ve adetini artırın... ";
            }
            if (this.textBox11.Text == "")
            {
                this.AdetAlt = 0.0;
            }
            else
            {
                this.AdetAlt = Convert.ToDouble(this.textBox11.Text);
            }
            this.KirisGerilme = (this.Gtu * this.LAlt) / ((2.0 * this.AdetAlt) * this.WAlt);
            if (this.KirisGerilme < 180.0)
            {
                this.frmh2.dataGridView1.Rows[2].Cells[1].Style.BackColor = Color.White;
                this.frmh2.dataGridView1[0, 2].Value = "3";
                this.frmh2.dataGridView1[1, 2].Value = "KABİN ALT  KİRİŞLERİNDE \x00c7ARPMADAN DOLAYI DOĞAN EĞİLME UYGUNDUR !";
                this.frmh2.dataGridView1[2, 2].Value = true;
            }
            else
            {
                this.frmh2.dataGridView1[0, 2].Value = "3";
                this.frmh2.dataGridView1.Rows[2].Cells[1].Style.BackColor = Color.Red;
                this.frmh2.dataGridView1[1, 2].Value = "KABİN ALT  KİRİŞLERİNDE \x00c7ARPMADAN DOLAYI DOĞAN EĞİLME UYGUN DEĞİLDİR !";
                this.frmh2.dataGridView1[2, 2].Value = false;
                this.frmh2.dataGridView1[3, 2].Value = "Alt askı kirişi değeri ve adetini artırın...";
            }
            if (this.textBox58.Text == "")
            {
                this.KirisYuk = 0.0;
            }
            else
            {
                this.KirisYuk = Convert.ToDouble(this.textBox58.Text);
            }
            this.Mee2 = ((this.gn * this.Byük) / 4.0) * (this.ygenislik / 2.0);
            this.GerilmeTOP = ((this.Mee2 * this.xderinlik) / ((4.0 * this.KirisYuk) * this.WYan)) + ((this.gn * this.Byük) / (2.0 * this.AYan));
            if (this.GerilmeTOP < 180.0)
            {
                this.frmh2.dataGridView1.Rows[3].Cells[1].Style.BackColor = Color.White;
                this.frmh2.dataGridView1[0, 3].Value = "4";
                this.frmh2.dataGridView1[1, 3].Value = "KABİN YAN ASKI K\x00d6ŞEBENTLERİNDE EĞİLME HESABI UYGUNDUR !";
