                this.frmh2.dataGridView1.Rows[3].Cells[1].Style.BackColor = Color.Red;
                this.frmh2.dataGridView1[1, 3].Value = "KABİN YAN ASKI K\x00d6ŞEBENTLERİNDE EĞİLME HESABI UYGUN DEĞİLDİR !";
                this.frmh2.dataGridView1[2, 3].Value = false;
                this.frmh2.dataGridView1[3, 3].Value = "Yan askı kirişi değeri ve kiriş y\x00fcksekliğini artırın...";
            }
            this.Atalet = Math.Sqrt((4.0 * this.LxYan) / this.AYan);
            if ((this.xderinlik / this.Atalet) < 120.0)
            {
                this.frmh2.dataGridView1.Rows[4].Cells[1].Style.BackColor = Color.White;
