        public void eylemsizlik()
        {
            MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
            connection.Open();
            MySqlDataReader reader = new MySqlCommand("select  imm  from   ray where model='" + this.KabinRayStr.Text + "'", connection).ExecuteReader();
            try
            {
                if (reader.HasRows)
                {
                    while (reader.Read())
                    {
                        this.eylemcap = Convert.ToDouble(reader[0].ToString());
                    }
                }
            }
            catch (Exception)
            {
                MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
            }
            finally
            {
                connection.Close();
            }
        }

