        private string griddendonen(string gelen)
        {
            for (int i = 0; i < this.gridView1.RowCount; i++)
            {
                if (this.gridView1.GetRowCellValue(i, "ParamName").ToString() == gelen)
                {
                    return this.gridView1.GetRowCellValue(i, "ParamValue").ToString();
                }
            }
            return "";
        }

        private void gridView1_CellValueChanged(object sender, CellValueChangedEventArgs e)
        {
            this.xx.oleupdate("update Num1 set " + e.Column.FieldName + " ='" + e.Value.ToString() + "' where ParamName='" + this.gridView1.GetRowCellValue(e.RowHandle, "ParamName").ToString() + "'", "");
        }

        public void halatk()
        {
            MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
            connection.Open();
            MySqlDataReader reader = new MySqlCommand("select hkut from halat where cap ='" + this.HalatCap.Text + "'", connection).ExecuteReader();
            try
            {
                if (reader.HasRows)
                {
                    while (reader.Read())
                    {
                        this.Hküt = Convert.ToDouble(reader[0].ToString());
                    }
                }
            }
            catch (Exception)
            {
                MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
            }
            finally
            {
                connection.Close();
            }
        }

        public void HalatSec()
        {
            MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
            connection.Open();
            MySqlCommand command = new MySqlCommand("select cap from halat", connection);
            try
            {
                if (command.Connection.State == ConnectionState.Closed)
                {
                    command.Connection.Open();
                }
                MySqlDataReader reader = command.ExecuteReader();
                if (reader.HasRows)
                {
                    while (reader.Read())
                    {
                        this.HalatCap.Properties.Items.Add(Convert.ToDecimal(reader.GetValue(0)));
                        this.RegHalatCap.Properties.Items.Add(reader.GetValue(0));
                    }
                }
            }
            catch (Exception)
            {
                MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
            }
            finally
            {
                connection.Close();
            }
        }

