        public void hangi(SearchLookUpEdit s, string mlz)
        {
            try
            {
                if (Convert.ToInt32(s.EditValue) > 0)
                {
                    int num = s.Properties.GetIndexByKeyValue(s.EditValue);
                    DataRow row = (s.Properties.DataSource as DataTable).Rows[num];
                    this.resim(row["uretici"].ToString(), mlz, row["model"].ToString(), Convert.ToBoolean(row["degisti"]));
                }
                else
                {
                    MessageBox.Show("\x00d6nce firma se\x00e7iniz");
                }
            }
            catch (Exception exception)
            {
                MessageBox.Show("Programı zorlamayınız" + exception.ToString());
            }
        }

