        public void IxAgirlikBul()
        {
            if (this.AgrRayStr.SelectedIndex != -1)
            {
                MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
                connection.Open();
                MySqlDataReader reader = new MySqlCommand("select  Lxx  from  ray where model='" + this.AgrRayStr.Text + "'", connection).ExecuteReader();
                try
                {
                    if (reader.HasRows)
                    {
                        while (reader.Read())
                        {
                            this.IxAgirlik = Convert.ToDouble(reader[0].ToString()) * 10000.0;
                        }
                    }
                }
                catch (Exception)
                {
                    MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
                }
                finally
                {
                    connection.Close();
                }
            }
        }

