        public void KarsiAgirlik()
        {
            this.Fx = 0.0;
            this.Fx = ((((this.k2 * this.gn) * ((this.denge * this.Byük) + ((this.Kaküt + this.KapiAgirlik) + this.SusAgirlik))) * 0.1) * this.Dx) / (this.KARA * this.Apamesafe);
            this.My = 0.0;
            this.My = ((3.0 * this.Fx) * this.lk) / 16.0;
            this.GerilmeY = 0.0;
            this.GerilmeY = this.My / this.WyAgirlik;
            this.Fy = 0.0;
            this.Fy = ((((this.k2 * this.gn) * ((this.denge * this.Byük) + ((this.Kaküt + this.KapiAgirlik) + this.SusAgirlik))) * 0.05) * this.Dy) / ((this.KARA / 2.0) * this.Apamesafe);
            this.Mx = 0.0;
            this.Mx = ((3.0 * this.Fy) * this.lk) / 16.0;
            this.GerilmeX = 0.0;
            this.GerilmeX = this.Mx / this.WxAgirlik;
        }

        public void karsiraybilgileri()
        {
            if (this.AgrRayStr.SelectedIndex != -1)
            {
                MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
                connection.Open();
                MySqlDataReader reader = new MySqlCommand(" select s,Q,e,Lxx,wxx,imm,Lyy,wyy,iyy,g,c from ray where model='" + this.AgrRayStr.Text + "'", connection).ExecuteReader();
                try
                {
                    if (reader.HasRows)
                    {
                        int num = 0;
                        while (reader.Read())
                        {
                            if (num == 0)
                            {
                                this.Bir1 = Convert.ToDouble(reader[0].ToString());
                                this.Iki2 = Convert.ToDouble(reader[1].ToString());
                                this.Uc3 = Convert.ToDouble(reader[2].ToString());
                                this.Dort4 = Convert.ToDouble(reader[3].ToString());
                                this.Bes5 = Convert.ToDouble(reader[4].ToString());
                                this.Alti6 = Convert.ToDouble(reader[5].ToString());
                                this.Yedi7 = Convert.ToDouble(reader[6].ToString());
                                this.Sekiz8 = Convert.ToDouble(reader[7].ToString());
                                this.Dokuz9 = Convert.ToDouble(reader[8].ToString());
                                this.On10 = Convert.ToDouble(reader[9].ToString());
