        public void KirisSec()
        {
            MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
            connection.Open();
            MySqlCommand command = new MySqlCommand(" select isim  from  kiris", connection);
            try
            {
                if (command.Connection.State == ConnectionState.Closed)
                {
                    command.Connection.Open();
                }
                MySqlDataReader reader = command.ExecuteReader();
                if (reader.HasRows)
                {
                    while (reader.Read())
                    {
                        this.comboBox35.Properties.Items.Add(reader.GetValue(0));
                        this.comboBox34.Properties.Items.Add(reader.GetValue(0));
                    }
                }
            }
            catch (Exception)
            {
                MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
            }
            finally
            {
                connection.Close();
            }
        }

