        public void koduazalt(SearchLookUpEdit s, string uretici, string model, string no, string belge, string nobo)
        {
            try
            {
                if (s.Text != "")
                {
                    int num = s.Properties.GetIndexByKeyValue(s.EditValue);
                    DataRow row = (s.Properties.DataSource as DataTable).Rows[num];
                    this.findandreplace(this.appword, uretici, row["uretici"].ToString());
                    this.findandreplace(this.appword, model, row["model"].ToString());
                    this.findandreplace(this.appword, no, row["serino"].ToString());
                    this.findandreplace(this.appword, belge, row["belgeveren"].ToString());
                    this.findandreplace(this.appword, nobo, row["nobo"].ToString());
                }
                else
                {
                    this.findandreplace(this.appword, uretici, "");
                    this.findandreplace(this.appword, model, "");
                    this.findandreplace(this.appword, no, "");
                    this.findandreplace(this.appword, belge, "");
                    this.findandreplace(this.appword, nobo, "");
                }
            }
            catch (Exception)
            {
            }
        }

