        public void NormalDurum1()
        {
            this.Xq = 0.0;
            this.Yq = 0.0;
            this.Xq = this.xderinlik / 8.0;
            this.Fx = 0.0;
            this.Fx = ((this.k2 * this.gn) * ((this.Byük * (this.Xq - this.Xs)) + (((this.Kaküt + this.KapiAgirlik) + this.SusAgirlik) * (this.Xp - this.Xs)))) / (this.KRA * this.pamesafe);
            this.My = 0.0;
            this.My = ((3.0 * this.Fx) * this.lk) / 16.0;
            this.GerilmeY = 0.0;
            this.GerilmeY = this.My / this.Wy;
            this.Fy = 0.0;
            this.Fy = ((this.k2 * this.gn) * ((this.Byük * (this.Yq - this.Ys)) + (((this.Kaküt + this.KapiAgirlik) + this.SusAgirlik) * (this.Yp - this.Ys)))) / ((this.KRA / 2.0) * this.pamesafe);
            this.Mx = 0.0;
            this.Mx = ((3.0 * this.Fy) * this.lk) / 16.0;
            this.GerilmeX = 0.0;
            this.GerilmeX = this.Mx / this.Wx;
            this.GerilmeM1 = 0.0;
            this.GerilmeM1 = this.GerilmeX + this.GerilmeY;
            this.normaldurum1deg = Math.Round(this.GerilmeM1, 2);
        }

