        public void omega370bul1()
        {
            this.narintam = Convert.ToInt16(Math.Floor(this.narinlik));
            if ((this.narintam >= 20) && (this.narintam <= 60))
            {
                this.omega370 = (0.0001292 * Math.Pow(this.narinlik, 1.89)) + 1.0;
            }
            else if ((this.narintam >= 0x3d) && (this.narintam <= 0x55))
            {
                this.omega370 = (4.627E-05 * Math.Pow(this.narinlik, 2.14)) + 1.0;
            }
            else if ((this.narintam >= 0x56) && (this.narintam <= 0x73))
            {
                this.omega370 = (1.711E-05 * Math.Pow(this.narinlik, 2.35)) + 1.04;
            }
            else if ((this.narintam >= 0x74) && (this.narintam <= 250))
            {
                this.omega370 = 0.00016887 * Math.Pow(this.narinlik, 2.0);
            }
        }

        public void omega520bul1()
        {
            this.narintam = Convert.ToInt16(Math.Floor(this.narinlik));
            if ((this.narintam >= 20) && (this.narintam <= 50))
            {
                this.omega520 = (8.24E-05 * Math.Pow(this.narinlik, 2.06)) + 1.021;
            }
            else if ((this.narintam >= 0x33) && (this.narintam <= 70))
            {
                this.omega520 = (1.895E-05 * Math.Pow(this.narinlik, 2.41)) + 1.05;
            }
            else if ((this.narintam >= 0x47) && (this.narintam <= 0x59))
            {
                this.omega520 = (2.447E-05 * Math.Pow(this.narinlik, 2.36)) + 1.03;
            }
            else if ((this.narintam >= 90) && (this.narintam <= 250))
            {
                this.omega520 = 0.0002533 * Math.Pow(this.narinlik, 2.0);
            }
        }

