        public void RaySec()
        {
            MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
            connection.Open();
            MySqlCommand command = new MySqlCommand("select model from ray", connection);
            try
            {
                if (command.Connection.State == ConnectionState.Closed)
                {
                    command.Connection.Open();
                }
                MySqlDataReader reader = command.ExecuteReader();
                if (reader.HasRows)
                {
                    while (reader.Read())
                    {
                        this.KabinRayStr.Properties.Items.Add(reader.GetValue(0));
                        this.AgrRayStr.Properties.Items.Add(reader.GetValue(0));
                        this.comboBox20.Properties.Items.Add(reader.GetValue(0));
                    }
                }
            }
            catch (Exception)
            {
                MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
            }
            finally
            {
                connection.Close();
            }
        }

        public string resim(string uret, string mal, string texti, bool icerdemi)
        {
            string str2 = "";
            string str3 = "";
            DataTable table = this.xx.dtta("select tedarikid,edit,model from tedarik where malzeme='" + mal + "' and model='" + texti + "'", "");
            for (int i = 0; i < table.Rows.Count; i++)
            {
                str2 = table.Rows[i][0].ToString();
                str3 = table.Rows[i][1].ToString();
            }
            try
            {
                string startuppath;
                if (icerdemi)
                {
                    startuppath = this.startuppath;
                }
                else
                {
                    startuppath = "http://www.as-cad.net/fcert";
                }
                Process.Start(startuppath + @"\sertifika\" + mal + @"\" + str2 + @"\" + str3);
            }
            catch (Exception exception)
            {
                MessageBox.Show("Hangi kapıdan gitceğimi s\x00f6yleyeydin iyiydi.");
                StreamWriter writer = new StreamWriter(@"C:\SZGBKM\asnhata.txt", true);
                writer.WriteLine("Resimi bulamıyor veya resim yok;" + exception.Message);
                writer.Close();
            }
            return "";
        }

