        private void textBox28_EditValueChanged(object sender, EventArgs e)
        {
            if (this.KabinDer.Text == "")
            {
                this.xderinlik = 0.0;
            }
            else
            {
                this.xderinlik = Convert.ToDouble(this.KabinDer.Text);
            }
            if (this.KabinGen.Text == "")
            {
                this.ygenislik = 0.0;
            }
            else
            {
                this.ygenislik = Convert.ToDouble(this.KabinGen.Text);
            }
            this.Asansorm2 = (this.ygenislik * this.xderinlik) / 1000000.0;
            if (this.Asansorm2 < 0.79)
            {
                this.enb = "4 'den Azdır!";
            }
            else if ((this.Asansorm2 >= 0.79) && (this.Asansorm2 < 0.98))
            {
                this.enb = "4'd\x00fcr!";
            }
            else if ((this.Asansorm2 >= 0.98) && (this.Asansorm2 < 1.17))
            {
                this.enb = "5'dir!";
            }
            else if ((this.Asansorm2 >= 1.17) && (this.Asansorm2 < 1.45))
            {
                this.enb = "6'dır!";
            }
            else if ((this.Asansorm2 >= 1.45) && (this.Asansorm2 < 1.73))
            {
                this.enb = "8'dir!";
            }
            else if ((this.Asansorm2 >= 1.73) && (this.Asansorm2 < 2.15))
            {
                this.enb = "10'dur!";
            }
            else if ((this.Asansorm2 >= 2.15) && (this.Asansorm2 < 2.57))
            {
                this.enb = "13'd\x00fcr!";
            }
            else if ((this.Asansorm2 >= 2.57) && (this.Asansorm2 < 3.24))
            {
                this.enb = "16'dır!";
            }
            else if ((this.Asansorm2 >= 3.24) && (this.Asansorm2 < 3.57))
            {
                this.enb = "21'dir!";
            }
            else if ((this.Asansorm2 >= 3.57) && (this.Asansorm2 < 4.0))
            {
                this.enb = "24'd\x00fcr!";
            }
            else
            {
                this.enb = "24'den Fazladır!";
            }
            this.label170.Text = "Taşınabilecek En Fazla İnsan Sayısı " + this.enb;
        }

