        private void veriesit(DataTable gelentab, TextEdit tee)
        {
            for (int i = 0; i < gelentab.Rows.Count; i++)
            {
                if (gelentab.Rows[i][0].ToString() == tee.Name)
                {
                    tee.EditValue = gelentab.Rows[i][1];
                    tee.BackColor = Color.PeachPuff;
                }
            }
        }

        public void WAltBul()
        {
            if (this.comboBox35.SelectedIndex != -1)
            {
                MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
                connection.Open();
                MySqlDataReader reader = new MySqlCommand(" select W from kiris where isim='" + this.comboBox35.Text + "'", connection).ExecuteReader();
                try
                {
                    if (reader.HasRows)
                    {
                        while (reader.Read())
                        {
                            this.WAlt = Convert.ToDouble(reader[0].ToString());
                        }
                    }
                }
                catch (Exception)
                {
                    MessageBox.Show("Hata Oluştu");
                }
                finally
                {
                    connection.Close();
                }
            }
        }

        public void wordle(object isim, object kayisim)
        {
            new FileInfo(this.startuppath + @"\Avan Trafik.doc").Delete();
            File.Copy(this.startuppath + @"\Yedek\Avan Trafik.doc", this.startuppath + @"\Avan Trafik.doc");
            this.saveFileDialog1.FileName = this.gridView1.GetRowCellValue(1, "ParamValue").ToString();
            string fileName = "";
            FileInfo info2 = new FileInfo(this.startuppath + @"\deneme.doc");
            if (info2.Exists)
            {
                info2.Delete();
            }
            try
            {
                this.missing1 = Missing.Value;
                object readOnly = false;
                this.dosyaadi = this.startuppath + @"\Avan Trafik.doc";
                this.appword = (Microsoft.Office.Interop.Word.Application) Activator.CreateInstance(Marshal.GetTypeFromCLSID(new Guid("000209FF-0000-0000-C000-000000000046")));
                this.adoc = null;
                isim = this.dosyaadi;
                this.appword.Visible = true;
                this.adoc = this.appword.Documents.Open(ref isim, ref this.missing1, ref readOnly, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1, ref this.missing1);
                this.adoc.Activate();
                this.findandreplace(this.appword, "#I#", this.KonsolMesafe.Text);
