        public void WxBul()
        {
            if (this.KabinRayStr.SelectedIndex != -1)
            {
                MySqlConnection connection = new MySqlConnection(this.xx.dtbase());
                connection.Open();
                MySqlDataReader reader = new MySqlCommand("select  wxx  from   ray where model='" + this.KabinRayStr.Text + "'", connection).ExecuteReader();
                try
                {
                    if (reader.HasRows)
                    {
                        while (reader.Read())
                        {
                            this.Wx = Convert.ToDouble(reader[0].ToString()) * 1000.0;
                        }
                    }
                }
                catch (Exception)
                {
                    MessageBox.Show("L\x00fctfen Programı Yorucak Hamleler Yapmayınız");
                }
                finally
                {
                    connection.Close();
                }
            }
        }

